{"code":"import json
import re

path_papers = locals()['var_function-call-12211220615769207414']
with open(path_papers, 'r') as f:
    papers = json.load(f)

path_cit = locals()['var_function-call-11859459418229751864']
with open(path_cit, 'r') as f:
    citations = json.load(f)

cit_map = {c['title']: c['citation_count'] for c in citations}

total_citations = 0
chi_papers = []

# Regex without special apostrophe
venue_regex = re.compile(r"(CHI|UbiComp|CSCW|DIS|IUI|PervasiveHealth|WWW|OzCHI|TEI|AH)\s*[']?\d{2,4}", re.IGNORECASE)

for p in papers:
    text = p['text'][:3000]
    title = p['filename'].replace(".txt", "")

    lines = text.split('\n')
    is_chi = False
    is_other = False

    # Check first few lines (Header)
    for line in lines[:5]:
        m = venue_regex.search(line)
        if m:
            v = m.group(1).upper()
            if "CHI" in v and "OZCHI" not in v:
                is_chi = True
            elif "CHI" not in v and "OZCHI" not in v:
                is_other = True
            elif "OZCHI" in v:
                is_other = True

    # Check Copyright/Permission block
    for line in lines:
        if "Copyright" in line or "Permission" in line or "ACM 978" in line:
            m = venue_regex.search(line)
            if m:
                v = m.group(1).upper()
                if "CHI" in v and "OZCHI" not in v:
                    is_chi = True
                elif "CHI" not in v and "OZCHI" not in v:
                    is_other = True
                elif "OZCHI" in v:
                    is_other = True

    if is_chi and not is_other:
        chi_papers.append(title)
        total_citations += int(cit_map.get(title, 0))
    elif not is_chi and not is_other:
        # Fallback for CHI
        if "Conference on Human Factors" in text[:1000]:
             chi_papers.append(title)
             total_citations += int(cit_map.get(title, 0))

print(f"Identified {len(chi_papers)} CHI papers.")
print(f"Total citations: {total_citations}")
print("__RESULT__:")
print(json.dumps(total_citations))"}

